 13тЖТ/**
 14тЖТ * Starts a new coroutine and returns its result as an implementation of [CompletableFuture].
 15тЖТ * The running coroutine is cancelled when the resulting future is cancelled or otherwise completed.
 16тЖТ *
 17тЖТ * The coroutine context is inherited from a [CoroutineScope], additional context elements can be specified with the [context] argument.
 18тЖТ * If the context does not have any dispatcher nor any other [ContinuationInterceptor], then [Dispatchers.Default] is used.
 19тЖТ * The parent job is inherited from a [CoroutineScope] as well, but it can also be overridden
 20тЖТ * with corresponding [context] element.
 21тЖТ *
 22тЖТ * By default, the coroutine is immediately scheduled for execution.
 23тЖТ * Other options can be specified via `start` parameter. See [CoroutineStart] for details.
 24тЖТ * A value of [CoroutineStart.LAZY] is not supported
 25тЖТ * (since `CompletableFuture` framework does not provide the corresponding capability) and
 26тЖТ * produces [IllegalArgumentException].
 27тЖТ *
 28тЖТ * See [newCoroutineContext][CoroutineScope.newCoroutineContext] for a description of debugging facilities that are available for newly created coroutine.
 29тЖТ *
 30тЖТ * @param context additional to [CoroutineScope.coroutineContext] context of the coroutine.
 31тЖТ * @param start coroutine start option. The default value is [CoroutineStart.DEFAULT].
 32тЖТ * @param block the coroutine code.
 33тЖТ */
 34тЖТpublic fun <T> CoroutineScope.future(
 35тЖТ    context: CoroutineContext = EmptyCoroutineContext,
 36тЖТ    start: CoroutineStart = CoroutineStart.DEFAULT,
 37тЖТ    block: suspend CoroutineScope.() -> T
 38тЖТ) : CompletableFuture<T> {
 39тЖТ    require(!start.isLazy) { "$start start is not supported" }
 40тЖТ    val newContext = this.newCoroutineContext(context)
 41тЖТ    val future = CompletableFuture<T>()
 42тЖТ    val coroutine = CompletableFutureCoroutine(newContext, future)
 43тЖТ    future.handle(coroutine) // Cancel coroutine if future was completed externally
 44тЖТ    coroutine.start(start, coroutine, block)
 45тЖТ    return future
 46тЖТ}
