 48тЖТprivate class CompletableFutureCoroutine<T>(
 49тЖТ    context: CoroutineContext,
 50тЖТ    private val future: CompletableFuture<T>
 51тЖТ) : AbstractCoroutine<T>(context, initParentJob = true, active = true), BiFunction<T?, Throwable?, Unit> {
 52тЖТ    override fun apply(value: T?, exception: Throwable?) {
 53тЖТ        cancel()
 54тЖТ    }
 55тЖТ
 56тЖТ    override fun onCompleted(value: T) {
 57тЖТ        future.complete(value)
 58тЖТ    }
 59тЖТ
 60тЖТ    override fun onCancelled(cause: Throwable, handled: Boolean) {
 61тЖТ        if (!future.completeExceptionally(cause) && !handled) {
 62тЖТ            // prevents loss of exception that was not handled by parent & could not be set to CompletableFuture
 63тЖТ            handleCoroutineException(context, cause)
 64тЖТ        }
 65тЖТ    }
 66тЖТ}
