114тЖТpublic fun <T> CompletionStage<T>.asDeferred(): Deferred<T> {
115тЖТ    val future = toCompletableFuture() // retrieve the future
116тЖТ    // Fast path if already completed
117тЖТ    if (future.isDone) {
118тЖТ        return try {
119тЖТ            @Suppress("UNCHECKED_CAST")
120тЖТ            CompletableDeferred(future.get() as T)
121тЖТ        } catch (e: Throwable) {
122тЖТ            // unwrap original cause from ExecutionException
123тЖТ            val original = (e as? ExecutionException)?.cause ?: e
124тЖТ            CompletableDeferred<T>().also { it.completeExceptionally(original) }
125тЖТ        }
126тЖТ    }
127тЖТ    val result = CompletableDeferred<T>()
128тЖТ    handle { value, exception ->
129тЖТ        try {
130тЖТ            if (exception == null) {
131тЖТ                // the future has completed normally
132тЖТ                result.complete(value)
133тЖТ            } else {
134тЖТ                // the future has completed with an exception, unwrap it consistently with fast path
135тЖТ                // Note: In the fast-path the implementation of CompletableFuture.get() does unwrapping
136тЖТ                result.completeExceptionally((exception as? CompletionException)?.cause ?: exception)
137тЖТ            }
138тЖТ        } catch (e: Throwable) {
139тЖТ            // We come here iff the internals of Deferred threw an exception during its completion
140тЖТ            handleCoroutineException(EmptyCoroutineContext, e)
141тЖТ        }
142тЖТ    }
143тЖТ    result.cancelFutureOnCompletion(future)
