147тЖТ/**
148тЖТ * Awaits for completion of [CompletionStage] without blocking a thread.
149тЖТ *
150тЖТ * This suspending function is cancellable.
151тЖТ * If the [Job] of the current coroutine is cancelled or completed while this suspending function is waiting, this function
152тЖТ * stops waiting for the completion stage and immediately resumes with [CancellationException][kotlinx.coroutines.CancellationException].
153тЖТ *
154тЖТ * This method is intended to be used with one-shot futures, so on coroutine cancellation the [CompletableFuture] that
155тЖТ * corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
156тЖТ * is cancelled. If cancelling the given stage is undesired, `stage.asDeferred().await()` should be used instead.
157тЖТ */
158тЖТpublic suspend fun <T> CompletionStage<T>.await(): T {
159тЖТ    val future = toCompletableFuture() // retrieve the future
160тЖТ    // fast path when CompletableFuture is already done (does not suspend)
161тЖТ    if (future.isDone) {
162тЖТ        try {
163тЖТ            @Suppress("UNCHECKED_CAST", "BlockingMethodInNonBlockingContext")
164тЖТ            return future.get() as T
165тЖТ        } catch (e: ExecutionException) {
166тЖТ            throw e.cause ?: e // unwrap original cause from ExecutionException
167тЖТ        }
168тЖТ    }
169тЖТ    // slow path -- suspend
170тЖТ    return suspendCancellableCoroutine { cont: CancellableContinuation<T> ->
171тЖТ        val consumer = ContinuationHandler(cont)
172тЖТ        handle(consumer)
173тЖТ        cont.invokeOnCancellation {
174тЖТ            future.cancel(false)
175тЖТ            consumer.cont = null // shall clear reference to continuation to aid GC
176тЖТ        }
177тЖТ    }
178тЖТ}
179тЖТ
180тЖТprivate class ContinuationHandler<T>(
181тЖТ    @Volatile @JvmField var cont: Continuation<T>?
182тЖТ) : BiFunction<T?, Throwable?, Unit> {
183тЖТ    @Suppress("UNCHECKED_CAST")
184тЖТ    override fun apply(result: T?, exception: Throwable?) {
185тЖТ        val cont = this.cont ?: return // atomically read current value unless null
186тЖТ        if (exception == null) {
187тЖТ            // the future has completed normally
188тЖТ            cont.resume(result as T)
189тЖТ        } else {
190тЖТ            // the future has completed with an exception, unwrap it to provide consistent view of .await() result and to propagate only original exception
191тЖТ            cont.resumeWithException((exception as? CompletionException)?.cause ?: exception)
192тЖТ        }
193тЖТ    }
